const markMessagesCompacted = `-- name: MarkMessagesCompacted :exec
UPDATE bot_history_messages
SET compact_id = ?1
WHERE id IN (/*SLICE:ids*/?)
`

type MarkMessagesCompactedParams struct {
	CompactID sql.NullString `json:"compact_id"`
	Ids       []string       `json:"ids"`
}

func (q *Queries) MarkMessagesCompacted(ctx context.Context, arg MarkMessagesCompactedParams) error {
	query := markMessagesCompacted
	var queryParams []interface{}
	queryParams = append(queryParams, arg.CompactID)
	if len(arg.Ids) > 0 {
		for _, v := range arg.Ids {
			queryParams = append(queryParams, v)
		}
		query = strings.Replace(query, "/*SLICE:ids*/?", strings.Repeat(",?", len(arg.Ids))[1:], 1)
	} else {
		query = strings.Replace(query, "/*SLICE:ids*/?", "NULL", 1)
	}
	_, err := q.db.ExecContext(ctx, query, queryParams...)
	return err
}

const searchMessages = `-- name: SearchMessages :many
WITH RECURSIVE visible_turns(id, parent_turn_id, depth) AS (
  SELECT t.id, t.parent_turn_id, 0
  FROM bot_sessions bs
  JOIN bot_history_turns t ON t.id = bs.default_head_turn_id
    AND t.bot_id = bs.bot_id
  WHERE ?2 IS NOT NULL
    AND bs.id = ?2
    AND bs.deleted_at IS NULL
  UNION ALL
  SELECT p.id, p.parent_turn_id, vt.depth + 1
  FROM bot_history_turns p
  JOIN visible_turns vt ON vt.parent_turn_id = p.id
)
SELECT
  m.id, m.bot_id, m.session_id, m.sender_channel_identity_id,
  m.role, m.content, m.created_at,
  ci.display_name AS sender_display_name,
  s.channel_type AS platform
FROM bot_history_messages m
LEFT JOIN channel_identities ci ON ci.id = m.sender_channel_identity_id
LEFT JOIN bot_sessions s ON s.id = m.session_id
WHERE m.bot_id = ?1
  AND (?2 IS NULL OR m.turn_id IN (SELECT id FROM visible_turns))
  AND (?3 IS NULL OR m.sender_channel_identity_id = ?3)
  AND (?4 IS NULL OR m.created_at >= strftime('%Y-%m-%d %H:%M:%S', ?4))
  AND (?5 IS NULL OR m.created_at <= strftime('%Y-%m-%d %H:%M:%S', ?5))
  AND (?6 IS NULL OR m.role = ?6)
  AND (?7 IS NULL OR (
    CASE
      WHEN NOT json_valid(m.content)
        THEN CASE WHEN m.content LIKE '%' || ?7 || '%' THEN m.content ELSE '' END
      WHEN json_type(json_extract(m.content, '$.content')) = 'text'
        THEN json_extract(m.content, '$.content')
      WHEN json_type(json_extract(m.content, '$.content')) = 'array'
        THEN (SELECT COALESCE(group_concat(json_extract(j.value, '$.text'), ' '), '')
              FROM json_each(json_extract(m.content, '$.content')) AS j
              WHERE json_extract(j.value, '$.type') = 'text')
      ELSE ''
    END
  ) LIKE '%' || ?7 || '%')
ORDER BY m.created_at DESC
LIMIT ?8
`

